INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'driver-insurance-essentials', '운전자보험 핵심 — 자동차보험과 무엇이 다를까', '교통사고처리지원금·벌금·변호사선임비용 등 운전자보험의 핵심 보장과, 자동차보험과의 차이를 정리했습니다.', '<p>자동차보험과 운전자보험은 이름이 비슷하지만 역할이 다릅니다. 자동차보험이 상대방·차량 손해를 보장한다면, 운전자보험은 운전자가 지는 형사·행정상 부담을 보완합니다.</p>
<h2>운전자보험의 대표 보장</h2>
<ul>
<li>교통사고처리지원금(형사합의금 등)</li>
<li>벌금</li>
<li>변호사선임비용</li>
</ul>
<h2>자동차보험과의 차이</h2>
<table>
<thead><tr><th>구분</th><th>자동차보험</th><th>운전자보험</th></tr></thead>
<tbody>
<tr><td>주 보장</td><td>대인·대물·자차 등 손해</td><td>형사·행정 부담 보완</td></tr>
<tr><td>성격</td><td>의무(책임보험 포함)</td><td>임의</td></tr>
</tbody>
</table>
<h2>가입 시 확인</h2>
<p>중대 과실 사고에서 형사 절차가 진행되면 합의금·변호사비 부담이 클 수 있습니다. 보장 항목과 한도, 보장에서 제외되는 사고 유형을 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>자동차보험=손해, 운전자보험=형사·행정 부담</li><li>처리지원금·벌금·변호사비가 핵심</li><li>한도·제외 사유 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","운전자보험","교통사고처리지원금"]', '[{"q":"자동차보험이 있으면 운전자보험은 필요 없나요?","a":"보장 영역이 다릅니다. 자동차보험은 손해를, 운전자보험은 형사합의금·벌금·변호사비 등 운전자 부담을 보완합니다."},{"q":"교통사고처리지원금이 무엇인가요?","a":"중대 사고 등에서 형사 합의에 쓰이는 비용을 보장하는 항목입니다. 한도와 조건은 약관을 확인하세요."},{"q":"모든 사고에 벌금이 보장되나요?","a":"보장·제외 사유가 약관에 정해져 있습니다. 음주 등 일부는 제외될 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'accident-settlement-and-criminal', '교통사고 후 합의와 형사 절차 — 기초 이해', '교통사고 후 민사 합의와 형사 처벌의 관계, 중과실 사고에서 운전자가 알아야 할 기본 절차를 정리했습니다.', '<p>교통사고는 손해배상(민사)과 별개로 형사 책임이 따를 수 있습니다. 둘의 관계를 알면 사고 후 대응이 한결 수월합니다.</p>
<h2>민사와 형사</h2>
<ul>
<li>민사: 피해 배상 — 보통 자동차보험으로 처리</li>
<li>형사: 처벌 — 중과실·중상해 등에서 문제</li>
</ul>
<h2>합의의 역할</h2>
<p>피해자와의 원만한 합의는 형사 절차에서 양형에 영향을 줄 수 있습니다. 중대 사고에서는 형사합의금 부담이 커, 운전자보험의 교통사고처리지원금이 도움이 됩니다.</p>
<table>
<thead><tr><th>구분</th><th>처리</th></tr></thead>
<tbody>
<tr><td>피해 배상</td><td>자동차보험(대인·대물)</td></tr>
<tr><td>형사 합의</td><td>운전자보험 등 활용</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>12대 중과실, 사망·중상해 등은 형사 처벌 가능성이 높습니다. 사고 직후 증거 확보와 함께, 필요한 경우 전문가(변호사) 도움을 받는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>민사 배상과 형사 처벌은 별개</li><li>합의는 양형에 영향</li><li>중과실 사고는 전문가 도움 검토</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","교통사고합의","형사절차"]', '[{"q":"보험으로 처리하면 형사 책임도 끝나나요?","a":"아닙니다. 보험은 주로 민사 배상을 처리하며, 중과실·중상해 등은 형사 책임이 별도로 따를 수 있습니다."},{"q":"합의가 꼭 필요한가요?","a":"중대 사고에서 피해자와의 합의는 형사 양형에 영향을 줄 수 있어 중요합니다."},{"q":"형사합의금은 어떻게 마련하나요?","a":"운전자보험의 교통사고처리지원금 등으로 보완할 수 있습니다. 한도를 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('whole-life', 'annuity-insurance-basics', '연금보험 기초 — 세제적격과 비적격의 차이', '노후 준비 수단인 연금보험의 세제적격(연금저축)과 세제비적격(연금보험)의 차이를 쉽게 정리했습니다.', '<p>연금보험은 노후 자금을 마련하는 대표 상품입니다. 크게 세제적격과 세제비적격으로 나뉘며, 세제 혜택과 과세 방식이 다릅니다.</p>
<h2>세제적격(연금저축)</h2>
<ul>
<li>납입 시 세액공제 혜택</li>
<li>연금 수령 시 연금소득세 과세</li>
</ul>
<h2>세제비적격(일반 연금보험)</h2>
<ul>
<li>납입 시 세액공제는 없음</li>
<li>비과세 요건을 충족하면 수령 시 세제상 유리할 수 있음</li>
</ul>
<table>
<thead><tr><th>구분</th><th>세제적격</th><th>세제비적격</th></tr></thead>
<tbody>
<tr><td>납입 단계</td><td>세액공제</td><td>혜택 없음</td></tr>
<tr><td>수령 단계</td><td>연금소득세</td><td>요건 충족 시 비과세 가능</td></tr>
</tbody>
</table>
<h2>선택 기준</h2>
<p>당장 세액공제로 절세하고 싶으면 세제적격이, 장기 비과세와 유연한 수령을 원하면 세제비적격이 맞을 수 있습니다. 세법은 바뀔 수 있으니 최신 기준을 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>세제적격=납입 공제·수령 과세</li><li>세제비적격=요건 충족 시 비과세 가능</li><li>절세 시점·목적으로 선택</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["종신보험","연금보험","노후준비"]', '[{"q":"연금저축과 연금보험은 같은 건가요?","a":"연금저축은 세제적격(납입 세액공제), 일반 연금보험은 세제비적격으로 과세 방식이 다릅니다."},{"q":"세액공제를 받으면 무조건 유리한가요?","a":"납입 시 공제 대신 수령 시 연금소득세가 있습니다. 절세 시점과 노후 계획에 따라 유불리가 갈립니다."},{"q":"비과세 요건은 무엇인가요?","a":"유지기간·납입 방식 등 법에서 정한 요건을 충족해야 합니다. 세법 변경 가능성이 있어 최신 기준 확인이 필요합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('whole-life', 'savings-insurance-basics', '저축성보험과 비과세 — 보장보다 적립이 목적이라면', '저축성보험의 구조와 보장성보험과의 차이, 비과세 혜택의 일반 요건과 유의점을 정리했습니다.', '<p>저축성보험은 보장보다 적립(저축)에 무게를 둔 상품입니다. 보장성보험과 목적이 달라, 기대와 다르게 운용되지 않도록 구조를 이해해야 합니다.</p>
<h2>보장성 vs 저축성</h2>
<table>
<thead><tr><th>구분</th><th>보장성</th><th>저축성</th></tr></thead>
<tbody>
<tr><td>주목적</td><td>위험 보장</td><td>자금 적립</td></tr>
<tr><td>환급</td><td>적거나 없음</td><td>적립금 형성</td></tr>
</tbody>
</table>
<h2>비과세 혜택</h2>
<p>저축성보험은 법에서 정한 유지기간·납입 요건 등을 충족하면 보험차익에 비과세 혜택이 적용될 수 있습니다. 다만 중도 해지하거나 요건을 못 채우면 혜택을 받지 못할 수 있습니다.</p>
<h2>유의점</h2>
<ul>
<li>초기에 사업비가 반영되어 단기 해지 시 원금 손실 가능</li>
<li>은행 예금과 단순 비교는 부적절(보장·세제·유동성 차이)</li>
</ul>
<p>저축성보험은 장기 유지를 전제로 한 상품이므로, 단기 자금이라면 적합하지 않을 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>저축성=적립 목적</li><li>요건 충족 시 보험차익 비과세 가능</li><li>장기 유지 전제, 단기 자금엔 부적합</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["종신보험","저축성보험","비과세"]', '[{"q":"저축성보험은 예금보다 좋나요?","a":"보장·세제·유동성이 달라 단순 비교는 어렵습니다. 장기 유지와 비과세 요건을 전제로 한 상품입니다."},{"q":"비과세는 항상 되나요?","a":"법에서 정한 유지기간·납입 요건 등을 충족해야 합니다. 중도 해지 시 혜택을 못 받을 수 있습니다."},{"q":"단기 자금으로 적합한가요?","a":"초기 사업비로 단기 해지 시 손실이 날 수 있어 단기 자금에는 부적합할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('terms', 'policy-loan-basics', '약관대출(보험계약대출) — 해지 없이 급전 마련하기', '해지환급금 범위 내에서 받는 약관대출의 구조와 이자, 미상환 시 영향을 정리해 합리적 활용을 돕습니다.', '<p>급하게 돈이 필요할 때 보험을 해지하기 전에 고려할 수 있는 것이 약관대출(보험계약대출)입니다. 보장을 유지하면서 자금을 마련할 수 있습니다.</p>
<h2>약관대출의 구조</h2>
<ul>
<li>해지환급금의 일정 범위 내에서 대출</li>
<li>심사 없이 비교적 간편하게 이용 가능</li>
<li>대출 이자가 발생</li>
</ul>
<h2>장점과 유의점</h2>
<table>
<thead><tr><th>장점</th><th>유의점</th></tr></thead>
<tbody>
<tr><td>보장 유지</td><td>이자 부담</td></tr>
<tr><td>간편 이용</td><td>미상환 시 환급금에서 차감</td></tr>
</tbody>
</table>
<h2>해지보다 나은 경우</h2>
<p>해지하면 환급금 손실과 보장 상실이 동시에 발생합니다. 일시적 자금 수요라면 약관대출로 보장을 유지하면서 넘기는 것이 유리할 수 있습니다. 다만 이자가 쌓이면 환급금이 줄 수 있어 계획적 상환이 필요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>해지환급금 범위 내 대출</li><li>보장 유지·간편 이용, 이자 발생</li><li>미상환 시 환급금에서 차감</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["약관해설","약관대출","보험계약대출"]', '[{"q":"약관대출은 신용에 영향을 주나요?","a":"내 보험의 해지환급금을 담보로 하는 대출이라 일반 신용대출과 성격이 다릅니다. 다만 상품·기관에 따라 다를 수 있어 확인이 필요합니다."},{"q":"안 갚으면 어떻게 되나요?","a":"미상환 원리금은 보험금이나 해지환급금에서 차감됩니다. 이자가 쌓이면 환급금이 줄 수 있습니다."},{"q":"해지와 약관대출 중 무엇이 나을까요?","a":"일시적 자금 수요라면 보장을 유지하는 약관대출이 유리한 경우가 많습니다. 계획적 상환이 전제입니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('terms', 'beneficiary-and-policyholder-change', '계약자·수익자 변경 — 누구 이름으로 둘까', '계약자와 수익자의 차이, 변경 절차와 변경 시 고려할 보장·세제 영향을 정리했습니다.', '<p>보험은 계약자, 피보험자, 수익자를 누구로 정하느냐에 따라 권리와 결과가 달라집니다. 상황 변화에 맞춰 변경이 필요할 수 있습니다.</p>
<h2>역할 구분</h2>
<ul>
<li>계약자: 계약 체결·보험료 납입, 계약상 권리 행사</li>
<li>피보험자: 보장의 대상</li>
<li>수익자: 보험금을 받는 사람</li>
</ul>
<h2>변경 절차</h2>
<p>계약자·수익자 변경은 보통 보험사에 신청해 처리합니다. 피보험자 변경은 일반적으로 제한됩니다(계약의 핵심 요소). 변경 시 관련자의 동의가 필요한 경우가 있습니다.</p>
<table>
<thead><tr><th>변경</th><th>가능성</th></tr></thead>
<tbody>
<tr><td>계약자</td><td>가능(절차·동의 필요)</td></tr>
<tr><td>수익자</td><td>가능</td></tr>
<tr><td>피보험자</td><td>원칙적 제한</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>계약자·수익자 지정과 변경은 보험금 귀속과 세제에 영향을 줄 수 있습니다. 특히 자금 출처와 수령자가 다르면 과세 문제가 생길 수 있어 사전 검토가 필요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>계약자·피보험자·수익자 역할 구분</li><li>피보험자 변경은 원칙적 제한</li><li>변경은 보험금 귀속·세제에 영향</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["약관해설","수익자변경","계약자변경"]', '[{"q":"수익자는 언제든 바꿀 수 있나요?","a":"일반적으로 계약자가 변경할 수 있습니다. 절차와 관련자 동의 요건을 보험사에 확인하세요."},{"q":"피보험자도 바꿀 수 있나요?","a":"피보험자는 계약의 핵심 요소라 원칙적으로 변경이 제한됩니다."},{"q":"변경하면 세금 문제가 생기나요?","a":"자금 출처와 수령자가 다르면 과세 문제가 생길 수 있습니다. 사전에 전문가 검토를 받는 것이 안전합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'insurance-tax-deduction', '보험료 세액공제 — 연말정산에서 챙기는 보장성보험', '연말정산 시 보장성보험료 세액공제의 일반 요건과 대상, 확인 방법을 정리했습니다(세법은 변경될 수 있음).', '<p>근로자라면 연말정산에서 보장성보험료에 대해 세액공제를 받을 수 있습니다. 요건과 대상을 알면 빠뜨리지 않고 챙길 수 있습니다.</p>
<h2>대상과 요건(일반)</h2>
<ul>
<li>보장성보험(실손·종신·상해 등)의 납입 보험료가 대상</li>
<li>근로소득자 본인·기본공제 대상 가족의 계약 등 요건 충족 필요</li>
<li>저축성보험료는 일반적으로 보장성 세액공제 대상이 아님</li>
</ul>
<h2>확인 방법</h2>
<p>연말정산 간소화 자료에서 보험료 납입 내역을 확인할 수 있습니다. 장애인전용 보장성보험은 별도 기준이 적용됩니다. 한도·공제율 등 구체적 수치는 해당 연도 세법 기준을 따릅니다.</p>
<table>
<thead><tr><th>구분</th><th>공제</th></tr></thead>
<tbody>
<tr><td>보장성보험료</td><td>세액공제 대상</td></tr>
<tr><td>저축성보험료</td><td>일반적으로 대상 아님</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>세법은 해마다 바뀔 수 있으므로 한도·공제율은 최신 기준을 확인하세요. 설계사라면 고객 안내 시 일반 요건만 설명하고 구체 수치는 국세청 기준을 권하는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>보장성보험료가 세액공제 대상</li><li>저축성은 일반적으로 제외</li><li>한도·율은 해당 연도 세법 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","세액공제","연말정산"]', '[{"q":"실손보험료도 세액공제가 되나요?","a":"보장성보험료로서 대상이 될 수 있습니다. 요건과 한도는 해당 연도 세법 기준을 확인하세요."},{"q":"저축성보험료도 공제되나요?","a":"일반적으로 보장성보험료 세액공제 대상이 아닙니다. 연금저축 등은 별도 제도입니다."},{"q":"얼마나 돌려받나요?","a":"한도와 공제율은 세법에 따라 정해지며 변경될 수 있습니다. 최신 기준을 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'medical-advice-dispute', '보험사 의료자문 — 내 진단이 뒤집힐 수 있을까', '보험금 심사 과정의 의료자문 제도가 무엇이며, 자문 결과에 이견이 있을 때의 대응을 정리했습니다.', '<p>보험금 심사에서 보험사가 제3의 의료기관에 의견을 묻는 의료자문 제도가 있습니다. 자문 결과가 지급 판단에 영향을 줄 수 있어 알아둘 필요가 있습니다.</p>
<h2>의료자문이란</h2>
<p>주치의 진단과 별개로, 보험사가 자문의에게 의학적 의견을 구하는 절차입니다. 자문 결과가 주치의 진단과 다를 경우 지급을 두고 다툼이 생길 수 있습니다.</p>
<h2>이견이 있을 때</h2>
<ul>
<li>주치의 소견을 보강(추가 검사·상세 소견서)</li>
<li>제3의 의료기관 감정(동시감정 등) 요청</li>
<li>합의가 안 되면 금융분쟁조정 활용</li>
</ul>
<table>
<thead><tr><th>상황</th><th>대응</th></tr></thead>
<tbody>
<tr><td>자문≠주치의</td><td>소견 보강·재감정</td></tr>
<tr><td>지급 거절</td><td>분쟁조정·민원</td></tr>
</tbody>
</table>
<h2>핵심</h2>
<p>의료자문은 어디까지나 의견입니다. 객관적 검사 자료와 주치의의 구체적 소견으로 맞서는 것이 중요하며, 자문의 동의·자료 제공 범위도 확인할 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>의료자문은 보험사 측 의견</li><li>주치의 소견·검사로 대응</li><li>합의 불가 시 분쟁조정</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","의료자문","분쟁"]', '[{"q":"의료자문으로 보험금이 거절될 수 있나요?","a":"자문 결과가 지급 판단에 영향을 줄 수 있습니다. 다만 의견일 뿐이므로 주치의 소견·검사로 대응할 수 있습니다."},{"q":"내 동의 없이 자문을 받나요?","a":"자료 제공·자문에는 동의·고지가 관련됩니다. 절차와 범위를 보험사에 확인할 수 있습니다."},{"q":"자문 결과가 부당하면요?","a":"소견 보강과 재감정을 요청하고, 합의가 안 되면 금융분쟁조정을 활용할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'small-claim-easy-filing', '소액 보험금 간편청구 — 빠르게 받는 법', '소액 의료비의 간편청구 요건과 모바일·간소화 서비스 활용법을 정리해 빠른 청구를 돕습니다.', '<p>소액 의료비는 서류를 간소화해 빠르게 청구할 수 있습니다. 절차를 알면 자주 쓰는 통원비도 번거롭지 않게 받을 수 있습니다.</p>
<h2>간편청구 요건</h2>
<ul>
<li>일정 금액 이하의 통원·약제비 등</li>
<li>진단서 없이 영수증·세부내역서로 가능한 경우가 많음</li>
</ul>
<h2>모바일·간소화 활용</h2>
<p>보험사 앱에서 서류를 촬영해 올리면 청구가 끝나는 경우가 많고, 일부 병원은 진료비 정보를 보험사로 바로 전송하는 간소화 서비스를 제공합니다.</p>
<table>
<thead><tr><th>방법</th><th>특징</th></tr></thead>
<tbody>
<tr><td>앱 사진 청구</td><td>가장 보편적</td></tr>
<tr><td>병원 간소화 전송</td><td>제공 기관에서 편리</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>금액이 커지거나 질병명 확인이 필요하면 진단서가 요구될 수 있습니다. 소액이라도 청구권 소멸시효(3년)가 있으니 모아서라도 챙겨 청구하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>소액은 영수증·세부내역서로 간편</li><li>앱·병원 간소화 서비스 활용</li><li>시효 3년 내 챙겨 청구</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","간편청구","소액"]', '[{"q":"소액은 진단서 없이 되나요?","a":"일정 금액 이하 통원은 영수증과 세부내역서만으로 가능한 경우가 많습니다. 보험사 기준을 확인하세요."},{"q":"앱으로만 청구해도 되나요?","a":"대부분 앱에서 서류를 촬영해 올리면 청구가 가능합니다. 원본 보관을 권합니다."},{"q":"소액도 기한이 있나요?","a":"청구권 소멸시효는 3년입니다. 소액이라도 기한 내 청구하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-mri-ct-coverage', 'MRI·CT 비급여 검사 — 실손으로 얼마나 보장될까', '고가 영상검사(MRI·CT)의 급여·비급여 구분과 세대별 실손 보장 차이, 청구 시 유의점을 정리했습니다.', '<p>MRI·CT 같은 영상검사는 비용이 커서 실손 보장 여부가 중요합니다. 급여·비급여 구분과 가입 세대에 따라 보장이 달라집니다.</p>
<h2>급여와 비급여</h2>
<ul>
<li>질환 의심으로 의학적 필요성이 인정되면 급여로 처리되는 경우</li>
<li>그 외 비급여 영상검사는 별도 기준·특약 적용</li>
</ul>
<h2>세대별 차이</h2>
<p>3·4세대 실손은 비급여 영상검사가 특약으로 분리되어 자기부담·한도가 따로 적용될 수 있습니다. 같은 검사라도 가입 세대에 따라 받는 금액이 다릅니다.</p>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>급여 처리</td><td>본인부담 보장</td></tr>
<tr><td>비급여</td><td>특약·한도 적용</td></tr>
</tbody>
</table>
<h2>청구 시</h2>
<p>검사의 의학적 필요성(진단명·소견)이 드러나는 자료를 확보하세요. 단순 확인 목적의 비급여 검사는 보장이 제한될 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>급여·비급여 구분이 보장 좌우</li><li>3·4세대는 비급여 특약 한도</li><li>의학적 필요성 자료 확보</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 세제는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 세제는 변경될 수 있으니 최신 기준을 확인하세요. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","MRI","비급여검사"]', '[{"q":"MRI도 실손이 되나요?","a":"의학적 필요성이 인정되면 보장될 수 있습니다. 급여·비급여 구분과 세대별 특약 한도를 확인하세요."},{"q":"세대마다 보장이 다른가요?","a":"3·4세대는 비급여 영상검사가 특약으로 분리되어 자기부담·한도가 별도로 적용됩니다."},{"q":"검사비가 비싼데 다 받나요?","a":"한도와 자기부담이 적용될 수 있습니다. 단순 확인 목적이면 보장이 제한될 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
